//vip.opstream12.com/20220511/15154_4623ea09/index.m3u8"}]}],"description":"<p>Một người phụ nữ đau buồn trước cái chết của con gái mình đã mất đi sự thực tế khi cô bắt đầu nghĩ rằng cô gái của mình có thể vẫn còn sống.</p>","tmdb_id":515741,"_supabaseOriginalSlug":"thien-than-nho-cua-me"},{"id":"627be9b1db9df06c659561ae","title":"Thuần Hóa","origin_name":"The Mustang","slug":"thuan-hoa","_from_supabase":true,"year":"2019","type":"single","genre":[{"name":"Tâm Lý","slug":"tam-ly"}],"country":[{"name":"Pháp","slug":"phap"},{"name":"Bỉ","slug":"bi"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","modified":"2022-05-11T16:52:01.000Z","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"name":"Vietsub #1","slug":"vietsub-1","server_name":"Vietsub #1","server_data":[{"name":"Full","slug":"full","link_embed":"https://vip.opstream12.com/share/f5532381792b4aafeb9e52a68bf568de","link_m3u8":"https://vip.opstream12.com/20220511/15155_9a785255/index.m3u8"}]}],"description":"<p>Phim giới thiệu về giống ngựa Mustang đầy hoang dã và dũng mãnh của miền viễn tây nước Mỹ. Với những đặc tính rất khó huấn luyện, chính phủ Mỹ dùng chúng như một công cụ giúp cho các tù nhân cùng nhau cải thiện tâm tính của mình. Roman Coleman là một ví dụ điển hình, anh cực kỳ nóng tính và thiếu kiên nhẫn. Tuy nhiên mọi chuyện đã khác kể từ khi anh được đăng ký vào chương trình huấn luyện ngựa hoang Mustang. Thông qua chú ngựa, anh đã nhớ lại nhiều thứ và nhận ra mình vẫn còn rất nhiều thứ quan trọng bên ngoài song sắt đang chờ đón anh.</p>","tmdb_id":500860,"_supabaseOriginalSlug":"thuan-hoa"},{"id":"627bea06db9df06c659561ee","title":"Vũ Điệu Đường Phố","origin_name":"Step Up 2: The Streets","slug":"vu-dieu-duong-pho","_from_supabase":true,"year":"2008","type":"single","genre":[{"name":"Tình Cảm","slug":"tinh-cam"},{"name":"Tâm Lý","slug":"tam-ly"}],"country":[{"name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","modified":"2022-05-11T16:53:26.000Z","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"name":"Vietsub #1","slug":"vietsub-1","server_name":"Vietsub #1","server_data":[{"name":"Full","slug":"full","link_embed":"https://vip.opstream12.com/share/f07bdaf0e636773c9932fa54a952bb50","link_m3u8":"https://vip.opstream12.com/20220511/15157_5ae11881/index.m3u8"}]}],"description":"<p>Lấy bối cảnh tại Trường Nghệ thuật Maryland, Step Up 2 the Street kể về những vũ công đường phố phá cách đang đấu tranh để được thừa nhận trong ngôi trường danh tiếng. Andie có thể là một vũ công tài năng đầy triển vọng nhưng cô lại không thể dứt bỏ cuộc sống cũ của mình để khởi đầu những điều mới mẻ. Khi cuộc thi khiêu vũ hot nhất Baltimore đang đến rất gần, Andie đã gia nhập nhóm của vũ công hàng đầu Chase đồng thời hướng dẫn các bạn cùng lớp nâng cao kỹ năng nhảy. Họ đã cùng nhau làm nên một màn trình diễn để đời...</p>","tmdb_id":8328,"_supabaseOriginalSlug":"vu-dieu-duong-pho"},{"id":"627bf8b4db9df06c65956a90","title":"Duyên Phận Đáng Sợ","origin_name":"Lovely Horribly","slug":"duyen-phan-dang-so","_from_supabase":true,"year":"2018","type":"series","genre":[{"name":"Tình Cảm","slug":"tinh-cam"},{"name":"Tâm Lý","slug":"tam-ly"},{"name":"Kinh Dị","slug":"kinh-di"}],"country":[{"name":"Hàn Quốc","slug":"han-quoc"}],"lang_key":"Thuyết Minh","episode_current":"Hoàn Tất (32/32)","quality":"HD","modified":"2022-05-11T17:56:04.000Z","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"name":"Thuyết Minh #1","slug":"vietsub-1","server_name":"Thuyết Minh #1","server_data":[{"name":"1","slug":"1","link_embed":"https://vip.opstream10.com/share/213b9c781a1cb3740d204492e6ce20c0","link_m3u8":"https://vip.opstream10.com/20220510/13102_f1c5625e/index.m3u8"},{"name":"2","slug":"2","link_embed":"https://vip.opstream10.com/share/aa25a165